415: export async function loadMailHeaders(entityClient: EntityClient, mailWrapper: MailWrapper): Promise<string | null> {
416: 	if (mailWrapper.isLegacy()) {
417: 		const headersId = mailWrapper.getMail().headers
418: 		return headersId != null ? getLegacyMailHeaders(await entityClient.load(MailHeadersTypeRef, headersId)) : null
419: 	} else {
420: 		const details = mailWrapper.getDetails()
421: 		return details.headers != null ? getMailHeaders(details.headers) : null
422: 	}
