431: export function getMailFilterForType(filter: MailFilterType | null): ListFilter<Mail> | null {
432: 	switch (filter) {
433: 		case MailFilterType.Read:
434: 			return (mail) => !mail.unread
435: 		case MailFilterType.Unread:
