47: 	async loadReverseRangeBetween<T extends ListElementEntity>(
48: 		typeRef: TypeRef<T>,
49: 		listId: Id,
50: 		start: Id,
51: 		end: Id,
52: 		rangeItemLimit: number = RANGE_ITEM_LIMIT,
53: 	): Promise<{
54: 		elements: T[]
55: 		loadedCompletely: boolean
56: 	}> {
57: 		const typeModel = await resolveTypeReference(typeRef)
58: 		if (typeModel.type !== Type.ListElement) throw new Error("only ListElement types are permitted")
59: 		const loadedEntities = await this._target.loadRange<T>(typeRef, listId, start, rangeItemLimit, true)
60: 		const filteredEntities = loadedEntities.filter((entity) => firstBiggerThanSecond(getElementId(entity), end, typeModel))
61: 
62: 		if (filteredEntities.length === rangeItemLimit) {
63: 			const lastElementId = getElementId(filteredEntities[loadedEntities.length - 1])
64: 			const { elements: remainingEntities, loadedCompletely } = await this.loadReverseRangeBetween<T>(typeRef, listId, lastElementId, end, rangeItemLimit)
65: 			return {
66: 				elements: filteredEntities.concat(remainingEntities),
67: 				loadedCompletely,
68: 			}
69: 		} else {
70: 			return {
71: 				elements: filteredEntities,
72: 				loadedCompletely: wasReverseRangeCompletelyLoaded(rangeItemLimit, loadedEntities, filteredEntities),
73: 			}
74: 		}
75: 	}
