110: 		const typeModel = await resolveTypeReference(typeRef)
111: 		const rootId = [groupId, typeModel.rootId] as const
112: 		const root = await this.load<RootInstance>(RootInstanceTypeRef, rootId)
113: 		return this.load<T>(typeRef, downcast(root.reference))
