/**
 * Regression test for non-legacy mail decryption key propagation bug
 *
 * Issue: Users with non-legacy (owner-encrypted) mails report blank message bodies,
 * missing reply-to addresses, and missing attachment listings. The root cause is that
 * encrypted session keys are not propagated when loading related entities (mail details).
 *
 * When MailIndexer.loadMailDetails calls loadInChunks to load MailDetailsBlob entities,
 * the session keys from the parent Mail object are not passed to the loadMultiple call.
 * This causes EntityRestClient to be unable to decrypt the entities, resulting in:
 * - Blank mail bodies
 * - Missing reply-to addresses
 * - Missing attachment listings
 * - Silent decryption failures with _errors set on entities
 *
 * Bug Location: src/api/worker/search/MailIndexer.ts:733-739
 * - loadInChunks() at line 785 calls loadMultiple() without providedOwnerEncSessionKeys
 *
 * Expected Fix: Pass a Map<Id, Uint8Array> of providedOwnerEncSessionKeys to loadMultiple
 * - Pattern: Similar to src/mail/model/MailUtils.ts:410
 */

import {
	aes128Encrypt,
	aes128RandomKey,
	ENABLE_MAC,
	encryptKey,
	IV_BYTE_LENGTH,
	random,
} from "@tutao/tutanota-crypto"
import {
	stringToUtf8Uint8Array,
	uint8ArrayToBase64,
} from "@tutao/tutanota-utils"
import {
	MailDetailsBlobTypeRef,
} from "../src/api/entities/tutanota/TypeRefs.js"
import { resolveTypeReference } from "../src/api/common/EntityFunctions.js"
import { InstanceMapper } from "../src/api/worker/crypto/InstanceMapper.js"

describe("Regression: Non-legacy mail decryption key propagation bug", () => {
	const instanceMapper = new InstanceMapper()

	test("MailDetailsBlob decryption fails when session key is not provided (BUG SCENARIO)", async () => {
		/**
		 * This test demonstrates the bug scenario:
		 * When a MailDetailsBlob is loaded without the _ownerEncSessionKey being set,
		 * decryption fails silently with _errors set on the instance.
		 */

		// Setup: Create session keys and encrypted content
		const mailGroupKey = aes128RandomKey() // The group key that would encrypt the session key
		const sessionKey = aes128RandomKey() // The session key for the mail details
		const body = "This is the mail body content"
		const replyTos = "reply@example.com"

		// Create a MailDetailsBlob literal with encrypted content
		const mailDetailsBlobLiteral: Record<string, any> = {
			_type: MailDetailsBlobTypeRef,
			_format: "0",
			_area: "0",
			_owner: "ownerId",
			_ownerGroup: "mailGroupId",
			// Missing: _ownerEncSessionKey would normally be here
			// This is what happens when loadInChunks doesn't pass providedOwnerEncSessionKeys
			_id: ["mailDetailsArchiveId", "mailDetailsBlobId"],
			_permissions: "permissionListId",
			details: {
				_type: { app: "tutanota", type: "MailDetails" },
				body: {
					_type: { app: "tutanota", type: "MailDetailsBlobBody" },
					compressedText: uint8ArrayToBase64(
						aes128Encrypt(sessionKey, stringToUtf8Uint8Array(body), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
					),
					text: null,
				},
				replyTos: [
					{
						_type: { app: "tutanota", type: "EncryptedMailAddress" },
						address: "reply@example.com",
						name: uint8ArrayToBase64(
							aes128Encrypt(sessionKey, stringToUtf8Uint8Array(replyTos), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
						),
					},
				],
				recipients: {
					_type: { app: "tutanota", type: "MailRecipients" },
					toRecipients: [],
					ccRecipients: [],
					bccRecipients: [],
				},
				sentDate: new Date(1470039021474).getTime(),
				headers: null,
			},
		}

		const MailDetailsBlobTypeModel = await resolveTypeReference(MailDetailsBlobTypeRef)

		// Try to decrypt without providing the session key
		// This should fail because the _ownerEncSessionKey is missing
		let decryptionFailed = false
		try {
			const decryptedBlob = await instanceMapper.decryptAndMapToInstance(
				MailDetailsBlobTypeModel,
				mailDetailsBlobLiteral,
				null, // No session key provided - this is the bug!
			)

			// If we get here, the body should have errors because decryption failed
			if (decryptedBlob._errors) {
				decryptionFailed = true
				console.log("✓ BUG CONFIRMED: Decryption failed silently with _errors set when session key not provided")
			}
		} catch (e) {
			// This is also acceptable - the decryption might throw
			decryptionFailed = true
			console.log("✓ BUG CONFIRMED: Decryption threw error when session key not provided")
		}

		// The test PASSES when the bug is present (decryption fails without session key)
		expect(decryptionFailed).toBe(true)
	})

	test("MailDetailsBlob decryption succeeds when session key is properly provided via _ownerEncSessionKey", async () => {
		/**
		 * This test shows the correct behavior:
		 * When _ownerEncSessionKey is present and we have the session key,
		 * decryption succeeds and we can access the encrypted content.
		 */

		// Setup: Create session keys and encrypted content
		const mailGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const body = "This is the mail body content"
		const replyTos = "reply@example.com"

		// Create a MailDetailsBlob literal with encrypted content AND the session key
		const mailDetailsBlobLiteral: Record<string, any> = {
			_type: MailDetailsBlobTypeRef,
			_format: "0",
			_area: "0",
			_owner: "ownerId",
			_ownerGroup: "mailGroupId",
			_ownerEncSessionKey: encryptKey(mailGroupKey, sessionKey), // Properly encrypted session key
			_id: ["mailDetailsArchiveId", "mailDetailsBlobId"],
			_permissions: "permissionListId",
			details: {
				_type: { app: "tutanota", type: "MailDetails" },
				body: {
					_type: { app: "tutanota", type: "MailDetailsBlobBody" },
					compressedText: uint8ArrayToBase64(
						aes128Encrypt(sessionKey, stringToUtf8Uint8Array(body), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
					),
					text: null,
				},
				replyTos: [
					{
						_type: { app: "tutanota", type: "EncryptedMailAddress" },
						address: "reply@example.com",
						name: uint8ArrayToBase64(
							aes128Encrypt(sessionKey, stringToUtf8Uint8Array(replyTos), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
						),
					},
				],
				recipients: {
					_type: { app: "tutanota", type: "MailRecipients" },
					toRecipients: [],
					ccRecipients: [],
					bccRecipients: [],
				},
				sentDate: new Date(1470039021474).getTime(),
				headers: null,
			},
		}

		const MailDetailsBlobTypeModel = await resolveTypeReference(MailDetailsBlobTypeRef)

		// Decrypt WITH the session key - this should work
		const decryptedBlob = await instanceMapper.decryptAndMapToInstance(
			MailDetailsBlobTypeModel,
			mailDetailsBlobLiteral,
			sessionKey, // Session key provided - decryption works
		)

		// Verify the decrypted content
		expect(decryptedBlob._errors).toEqual(undefined)
		expect(decryptedBlob.details.body.compressedText).toEqual(body)
		console.log("✓ Confirmed: Decryption succeeds when session key is properly provided")
	})

	test("MailDetailsBlob decryption succeeds with providedOwnerEncSessionKey injection pattern (CORRECT FIX)", async () => {
		/**
		 * This test shows the fix pattern already used in MailUtils.loadMailDetails:
		 *
		 * The providedOwnerEncSessionKey is injected onto the entity after loading,
		 * simulating what EntityRestClient._handleLoadMultipleResult does (line 276):
		 *   instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
		 *
		 * This is the pattern that should be used in MailIndexer.loadMailDetails as well.
		 */

		const mailGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const body = "This is the mail body content"
		const replyTos = "reply@example.com"

		// Create a MailDetailsBlob literal WITHOUT _ownerEncSessionKey on the literal itself
		const mailDetailsBlobLiteral: Record<string, any> = {
			_type: MailDetailsBlobTypeRef,
			_format: "0",
			_area: "0",
			_owner: "ownerId",
			_ownerGroup: "mailGroupId",
			// Note: NO _ownerEncSessionKey here - it will be injected separately
			_id: ["mailDetailsArchiveId", "mailDetailsBlobId"],
			_permissions: "permissionListId",
			details: {
				_type: { app: "tutanota", type: "MailDetails" },
				body: {
					_type: { app: "tutanota", type: "MailDetailsBlobBody" },
					compressedText: uint8ArrayToBase64(
						aes128Encrypt(sessionKey, stringToUtf8Uint8Array(body), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
					),
					text: null,
				},
				replyTos: [
					{
						_type: { app: "tutanota", type: "EncryptedMailAddress" },
						address: "reply@example.com",
						name: uint8ArrayToBase64(
							aes128Encrypt(sessionKey, stringToUtf8Uint8Array(replyTos), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
						),
					},
				],
				recipients: {
					_type: { app: "tutanota", type: "MailRecipients" },
					toRecipients: [],
					ccRecipients: [],
					bccRecipients: [],
				},
				sentDate: new Date(1470039021474).getTime(),
				headers: null,
			},
		}

		// Inject the _ownerEncSessionKey onto the literal after retrieval
		// This is what EntityRestClient._handleLoadMultipleResult should do (but doesn't when providedOwnerEncSessionKeys is not passed)
		mailDetailsBlobLiteral._ownerEncSessionKey = encryptKey(mailGroupKey, sessionKey)

		const MailDetailsBlobTypeModel = await resolveTypeReference(MailDetailsBlobTypeRef)

		// Now decrypt with the session key
		const decryptedBlob = await instanceMapper.decryptAndMapToInstance(
			MailDetailsBlobTypeModel,
			mailDetailsBlobLiteral,
			sessionKey,
		)

		// Verify success
		expect(decryptedBlob._errors).toEqual(undefined)
		expect(decryptedBlob.details.body.compressedText).toEqual(body)
		console.log("✓ Confirmed: The providedOwnerEncSessionKey injection pattern works correctly")
	})

	test("MailIndexer.loadMailDetails bug: loadInChunks does not pass session keys", async () => {
		/**
		 * This test explicitly demonstrates the actual bug in MailIndexer.loadMailDetails
		 *
		 * Current (buggy) code in MailIndexer.ts line 733:
		 *   const mailDetailsBlobs = await this.loadInChunks(MailDetailsBlobTypeRef, listId, ids)
		 *
		 * The loadInChunks method at line 785 calls:
		 *   this._entity.loadMultiple(typeRef, listId, chunk)
		 *
		 * But it DOES NOT pass the providedOwnerEncSessionKeys map!
		 * This means the loaded entities arrive at EntityRestClient._handleLoadMultipleResult
		 * without any session keys to inject.
		 *
		 * Correct implementation (from MailUtils.loadMailDetails line 410):
		 *   .loadMultiple(MailDetailsBlobTypeRef, listIdPart(mailDetailsId), [elementIdPart(mailDetailsId)], providedOwnerEncSessionKeys)
		 *
		 * The bug manifests as:
		 * 1. loadMultiple gets called WITHOUT providedOwnerEncSessionKeys
		 * 2. EntityRestClient._handleLoadMultipleResult has no session keys to inject
		 * 3. Entities get decrypted with sessionKey=null
		 * 4. Decryption fails, resulting in _errors being set on the instance
		 * 5. Mail bodies appear blank, reply-to addresses are missing, etc.
		 */

		const mailGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const body = "This is the mail body content"

		// Simulate what EntityRestClient._handleLoadMultipleResult does
		// when NO providedOwnerEncSessionKeys map is passed (the bug scenario)

		const mailDetailsBlobLiteral: Record<string, any> = {
			_type: MailDetailsBlobTypeRef,
			_format: "0",
			_area: "0",
			_owner: "ownerId",
			_ownerGroup: "mailGroupId",
			// _ownerEncSessionKey is NOT set because it wasn't passed to loadMultiple
			_id: ["mailDetailsArchiveId", "mailDetailsBlobId"],
			_permissions: "permissionListId",
			details: {
				_type: { app: "tutanota", type: "MailDetails" },
				body: {
					_type: { app: "tutanota", type: "MailDetailsBlobBody" },
					compressedText: uint8ArrayToBase64(
						aes128Encrypt(sessionKey, stringToUtf8Uint8Array(body), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC),
					),
					text: null,
				},
				replyTos: [],
				recipients: {
					_type: { app: "tutanota", type: "MailRecipients" },
					toRecipients: [],
					ccRecipients: [],
					bccRecipients: [],
				},
				sentDate: new Date(1470039021474).getTime(),
				headers: null,
			},
		}

		const MailDetailsBlobTypeModel = await resolveTypeReference(MailDetailsBlobTypeRef)

		// This simulates what happens when loadInChunks doesn't pass the session key
		const decryptedBlob = await instanceMapper.decryptAndMapToInstance(
			MailDetailsBlobTypeModel,
			mailDetailsBlobLiteral,
			null, // No session key because it wasn't propagated by loadInChunks
		)

		// The bug is confirmed: decryption fails silently
		expect(decryptedBlob._errors).not.toEqual(undefined)
		console.log("✓ Bug reproduced: Entity has _errors when session key is not propagated through loadInChunks")
	})

	test("Fix verification: Passing session keys through loadInChunks would solve the issue", async () => {
		/**
		 * This test shows how the bug would be fixed:
		 *
		 * In MailIndexer.loadMailDetails, the fix would be to:
		 * 1. Build a Map<Id, Uint8Array> of providedOwnerEncSessionKeys from the mails
		 * 2. Pass this map to loadInChunks
		 * 3. Have loadInChunks pass it to loadMultiple
		 *
		 * This ensures that when EntityRestClient._handleLoadMultipleResult is called (line 276),
		 * it can inject the session key:
		 *   instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
		 *
		 * Then decryption will succeed.
		 */

		const mailGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const body = "This is the mail body content"

		// Simulate the fixed version where session key IS provided
		const mailDetailsBlobLiteral: Record<string, any> = {
			_type: MailDetailsBlobTypeRef,
			_format: "0",
			_area: "0",
			_owner: "ownerId",
			_ownerGroup: "mailGroupId",
			// In the fixed version, this would be set by EntityRestClient._handleLoadMultipleResult
			// when providedOwnerEncSessionKeys is properly passed to loadMultiple
			_ownerEncSessionKey: encryptKey(mailGroupKey, sessionKey),
			_id: ["mailDetailsArchiveId", "mailDetailsBlobId"],
