import {
	aes128Encrypt,
	aes128RandomKey,
	ENABLE_MAC,
	encryptKey,
	IV_BYTE_LENGTH,
	random,
} from "@tutao/tutanota-crypto"
import {
	stringToUtf8Uint8Array,
	uint8ArrayToBase64,
